import{_ as e,o as r,c as d,ag as a}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt4907.jpg",i="/images/lekt4901.jpg",l="/images/lekt4902.jpg",s="/images/lekt4903.jpg",o="/images/lekt4904.jpg",u="/images/lekt4909.jpg",h="/images/lekt4905.jpg",b="/images/lekt4906.jpg",p="/images/lekt4908.jpg",w=JSON.parse('{"title":"Lektion 49","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion49.md","filePath":"lektionen/lektion49.md"}'),m={name:"lektionen/lektion49.md"};function c(k,t,g,f,q,P){return r(),d("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-49" tabindex="-1">Lektion 49 <a class="header-anchor" href="#lektion-49" aria-label="Permalink to &quot;Lektion 49&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>49.1. Bildung des Imperativs (लोट्) athematischer Präsensstämme (Fortsetzung) <ul><li>49.1.1. Siebte Präsensklasse  (रुधादि)</li><li>49.1.2. Fünfte Präsensklasse (स्वादि)</li><li>49.1.3. Achte Präsensklasse (तनादि)</li><li>49.1.4. Neunte Präsensklasse (क्र्यादि)</li></ul></li><li>49.2. Deklination der Nominalstämme auf -as, -is, -us</li><li>49.3. Nominalbildung: कृत्-Suffix -as Neutrum</li><li>49.4. Wortliste</li><li>49.5. Wiederholungsübung zur Formenlehre</li><li>49.6. Übersetzungsübung</li></ul><h2 id="_49-1-bildung-des-imperativs-लोट्-athematischer-prasensstamme-fortsetzung" tabindex="-1">49.1. Bildung des Imperativs (लोट्) athematischer Präsensstämme (Fortsetzung) <a class="header-anchor" href="#_49-1-bildung-des-imperativs-लोट्-athematischer-prasensstamme-fortsetzung" aria-label="Permalink to &quot;49.1. Bildung des Imperativs (लोट्) athematischer Präsensstämme (Fortsetzung)&quot;">​</a></h2><h3 id="_49-1-1-siebte-prasensklasse-रुधादि" tabindex="-1">49.1.1. Siebte Präsensklasse  (रुधादि) <a class="header-anchor" href="#_49-1-1-siebte-prasensklasse-रुधादि" aria-label="Permalink to &quot;49.1.1. Siebte Präsensklasse  (रुधादि)&quot;">​</a></h3><p>युज् 7U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>युनजानि</td><td></td></tr><tr><td>yu-na-j-āni</td><td>युनजाम</td><td>युनजै</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>युङ्ग्धि</td><td></td></tr><tr><td>yu-n-j + dhi</td><td></td><td></td></tr><tr><td>युङ्धि</td><td>युङ्क्त</td><td></td></tr><tr><td>युङ्त</td><td>युङ्क्ष्व</td><td>युङ्ग्ध्वं</td></tr><tr><td>युङ्ध्वम्</td><td></td><td></td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>युनक्तु</td><td></td></tr><tr><td>yu-na-j + tu</td><td>युञ्जन्तु</td><td>युङ्क्ताम्</td></tr><tr><td>यु्ङ्ताम्</td><td>युञ्जताम्</td><td></td></tr></tbody></table></blockquote><p>रुध् 7U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>रुणधानि</td><td></td></tr><tr><td>ru-ṇa-dh-āni</td><td>रुणधाम</td><td>रुणधै</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>रुन्द्धि</td><td>रुन्द्ध</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>रुणद्धु</td><td>रुन्धन्तु</td></tr></tbody></table></blockquote><h3 id="_49-1-2-funfte-prasensklasse-स्वादि" tabindex="-1">49.1.2. Fünfte Präsensklasse (स्वादि) <a class="header-anchor" href="#_49-1-2-funfte-prasensklasse-स्वादि" aria-label="Permalink to &quot;49.1.2. Fünfte Präsensklasse (स्वादि)&quot;">​</a></h3><p>Die 2.sg.P Imperativ ist endungslos bei Wurzeln der 5. und 8. Klasse, bei denen dem auslautenden -u des Suffixes nur ein Konsonant vorausgeht.</p><p>सु 5U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>सुनवानि</td><td>सुनवाम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>सुनु</td><td>सुनुत</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>सुनोतु</td><td>सुन्वन्तु</td></tr><tr><td>su-nu + atām</td><td></td><td></td></tr></tbody></table></blockquote><p>आप् 5P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>आप्नवानि</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>आप्नुहि</td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>आप्नोतु</td></tr></tbody></table></blockquote><h3 id="_49-1-3-achte-prasensklasse-तनादि" tabindex="-1">49.1.3. Achte Präsensklasse (तनादि) <a class="header-anchor" href="#_49-1-3-achte-prasensklasse-तनादि" aria-label="Permalink to &quot;49.1.3. Achte Präsensklasse (तनादि)&quot;">​</a></h3><p>तन् 8U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>तनवानि</td><td>तनवाम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>तनु</td><td>तनुत</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>तनोतु</td><td>तन्वन्तु</td></tr></tbody></table></blockquote><p>कृ 8U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>करवाणि</td><td>करवाम</td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>कुरु</td><td>कुरुत</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>करोतु</td><td>कुर्वन्तु</td></tr></tbody></table></blockquote><h3 id="_49-1-4-neunte-prasensklasse-क्र्यादि" tabindex="-1">49.1.4. Neunte Präsensklasse (क्र्यादि) <a class="header-anchor" href="#_49-1-4-neunte-prasensklasse-क्र्यादि" aria-label="Permalink to &quot;49.1.4. Neunte Präsensklasse (क्र्यादि)&quot;">​</a></h3><p>क्री 9U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>1. Person</td><td></td><td></td></tr><tr><td>तृतीयः</td><td>क्रीणानि</td><td></td></tr><tr><td>krī-ṇā + āni</td><td>क्रीणाम</td><td>क्रीणै</td></tr><tr><td>krī-ṇā + ai</td><td>क्रीणामहै</td><td></td></tr><tr><td>2. Person</td><td></td><td></td></tr><tr><td>मध्यमः</td><td>क्रीणीहि</td><td>क्रीणीत</td></tr><tr><td>3. Person</td><td></td><td></td></tr><tr><td>प्रथमः</td><td>क्रीणातु</td><td>क्रीणन्तु</td></tr><tr><td>krī-ṇ-antu</td><td>क्रीणीताम्</td><td>क्रीणताम्</td></tr></tbody></table></blockquote><p>Wurzeln der 9. Klasse, die auf Konsonant enden, ersetzen das auslautende -nī-hi der 2.sg.P Imperativ durch -āna</p><p>ग्रह् 9U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>1. Person</td><td></td></tr><tr><td>तृतीयः</td><td>गृह्णानि</td></tr><tr><td>2. Person</td><td></td></tr><tr><td>मध्यमः</td><td>गृहाण</td></tr><tr><td>3. Person</td><td></td></tr><tr><td>प्रथमः</td><td>गृह्णातु</td></tr></tbody></table></blockquote><h2 id="_49-2-deklination-der-nominalstamme-auf-as-is-us" tabindex="-1">49.2. Deklination der Nominalstämme auf -as, -is, -us <a class="header-anchor" href="#_49-2-deklination-der-nominalstamme-auf-as-is-us" aria-label="Permalink to &quot;49.2. Deklination der Nominalstämme auf -as, -is, -us&quot;">​</a></h2><h4 id="neutra-नपुंसक" tabindex="-1">Neutra (नपुंसक) <a class="header-anchor" href="#neutra-नपुंसक" aria-label="Permalink to &quot;Neutra (नपुंसक)&quot;">​</a></h4><p>|   | मनस् n.<br> &quot;Gedanke&quot; | हविस् n.<br> &quot;Opferspende&quot; | चक्षुस् n.<br> &quot;Auge&quot; | | --- | --- | --- | --- | | एकवचनम् |   |   |   | | प्रथमा, द्वितिया, आमन्त्रितम् | मनस् | हविस् | चक्षुस् | | तृतीया | मनसा | हविषा | चक्षुषा | | चतुर्थी | मनसे | हविषे | चक्षुषे | | पञ्चमी | मनसस् | हविषस् | कक्षुषस् | | षष्ठी | मनसस् | हविषस् | चक्षुषस् | | सप्तमी | मनसि | हविषि | चक्षुषि | | बहुवचनम् |   |   |   | | प्रथमा, द्वितिया, आमन्त्रितम् | मनांसि | हवींषि | चक्षूंषि | | तृतीया | मनोभिस् | हविर्भिस् | चक्षुर्भिस् | | चतुर्थी | मनोभ्यस् | हविर्भ्यस् | चक्षुर्भ्यस् | | पञ्चमी | मनोभ्यस् | हविर्भ्यस् | चक्षुर्भ्यस् | | षष्ठी | मनसाम् | हविषाम् | चक्षुषाम् | | सप्तमी | मनस्सु<br> मनःसु | हविष्षु<br> हविःषु | चक्षुष्षु<br> चक्षुःषु |</p><h4 id="maskulina-पुंस्-und-feminina-स्त्री" tabindex="-1">Maskulina (पुंस्) und Feminina (स्त्री) <a class="header-anchor" href="#maskulina-पुंस्-und-feminina-स्त्री" aria-label="Permalink to &quot;Maskulina (पुंस्) und Feminina (स्त्री)&quot;">​</a></h4><p>Die meisten Fälle sind बहुव्रीहि mit einem -s-Stamm (ursprünglich Neutrum) im Hinterglied.</p><p>|   | सुमनस् 3<br> &quot;von gutem Denken, wohlwollend | दीर्घायुस् 3<br> &quot;langlebig&quot; | | --- | --- | --- | | एकवचनम् |   |   | | प्रथम | सुमनास् | दीर्घायुस् | | द्विटिया | सुमनसम् | दीर्घायुषम् | | आमन्त्रितम् | सुमनस् | दीर्घायुस् | |</p><blockquote><p>Übrige Kasus des Singular wie Neutrum</p></blockquote><p>| | बहुवचनम् |   |   | | प्रथमा, द्वितिया, आमन्त्रितम् | सुमनसस् | दीर्घायुषस् | |</p><p>Übrige Kasus des Plural wie Neutrum</p><p>|</p><h2 id="_49-3-nominalbildung-कृत्-suffix-as-neutrum" tabindex="-1">49.3. Nominalbildung: कृत्-Suffix -as Neutrum <a class="header-anchor" href="#_49-3-nominalbildung-कृत्-suffix-as-neutrum" aria-label="Permalink to &quot;49.3. Nominalbildung: कृत्-Suffix -as Neutrum&quot;">​</a></h2><p>Mit dem कृत्-Suffix -as Neutrum werden zahlreiche Substantive gebildet. Meist sind es Abstrakta oder Nomina actionis (Wörter, die die Handlung bezeichnen).</p><p>Kurzer Vokal der Wurzel vor einfachem Konsonant sowie auslautender Wurzelvokal erscheinen in der Hochstufe.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>Nomen auf -as</th></tr></thead><tbody><tr><td>मन् 4Ā &quot;denken&quot;</td><td>मनस् n. &quot;Denken, Gedanke, Denkorgan&quot;</td></tr><tr><td>नम् 1P &quot;beugen&quot;</td><td>नमस् n. &quot;Verbeugung, Verehrung&quot;</td></tr><tr><td>चित् 1P &quot;wahrnehmen, denken&quot;</td><td>चेतस् n. &quot;Einsicht&quot;</td></tr></tbody></table></blockquote><p>Nomina auf -is und -us sind relativ selten.</p><p><img src="'+n+'" alt=""><br> Abb.: नमस्ते<br> [Bildquelle: Ragesh Vasudevan. -- <a href="http://www.flickr.com/photos/rageshev/2786703508/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/rageshev/2786703508/</a>. -- Zugriff am 2009-01-10. --  <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung,  keine kommerzielle Nutzung, share alike)]</p><h2 id="_49-4-wortliste" tabindex="-1">49.4. Wortliste <a class="header-anchor" href="#_49-4-wortliste" aria-label="Permalink to &quot;49.4. Wortliste&quot;">​</a></h2><p>दीर्घ 3: lange</p><p>ह्रस्व 3: kurz</p><p>आयुस् n.: Lebenszeit (die volle Lebenszeit, die man leben kann, wenn nichts dazwischen kommt) ;</p><blockquote><p>davon:</p><p>आयुर्वेद m.: das traditionelle medizinische System Indiens</p><p>siehe:</p><blockquote><blockquote><p>Carakasaṃhitā: Ausgewählte Texte aus der Carakasaṃhitā / übersetzt und erläutert von Alois Payer &lt;1944 - &gt;. -- 0. Einleitung. -- URL: <a href="http://www.payer.de/ayurveda/caraka0001.htm" target="_blank" rel="noreferrer">http://www.payer.de/ayurveda/caraka0001.htm</a></p></blockquote></blockquote></blockquote><p>क्षिप् 6P क्षिपति : werfen, schleudern</p><blockquote><p>Perf. II चिक्षेप, चिक्षेपिथ, चिक्षिपुर्<br> Fut. क्षेप्स्यति<br> Pass. क्षिप्यते<br> Kaus. क्षेपयति<br> PPP क्षिप्त<br> Inf. क्षेप्तुम्<br> Absol. -क्षिप्य<br> Gerundiv: क्षेप्य</p></blockquote><p>त्वर् 1Ā त्वरते : eilen</p><blockquote><p>Perf. Vc तत्वरे<br> Fut. त्वरिष्यते<br> Pass. त्वर्यते<br> Kaus. त्वरयति<br> PPP त्वरित । तू्र्ण<br> Inf. त्वरितुम्</p></blockquote><p>द्रुह् 4P द्रुह्यति : schädigen</p><blockquote><p>Perf. II दुद्रोह, दुद्रुहुर्<br> Fut. द्रोहिष्यति । ध्रोक्ष्यति<br> Pass. द्रुह्यते<br> Kaus. द्रोहयति<br> PPP द्रुग्ध । द्रूढ<br> Inf. द्रोग्धुम्</p></blockquote><p>कुलूहल n.: Neugier, Interesse</p><p><img src="'+i+'" alt=""><br> Abb.: कुलूहलम्<br> [Bildquelle: younee. -- <a href="http://www.flickr.com/photos/younee/1708474353/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/younee/1708474353/</a>. -- Zugriff am 2009-01-11. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine Bearbeitung)]</p><p>कृत्स्न 3: ganz, vollständig</p><p>परिचय m.: Bekanntschaft</p><p>कला f.: Kunst</p><p><img src="'+l+'" alt=""><br> Abb.: उत्तमा काला<br> शिवो नटराजा, 11. Jhdt.<br> [Bildquelle: Vassil / Wikipedia. Public domain]</p><p>वर m.n.: Wunsch</p><p>उत Indekl.: und, auch, oder</p><p>विहंग m.: Vogel (&quot;in den Lufस्traum - विह - gehend&quot;)</p><p><img src="'+s+'" alt=""><br> Abb.: विहंगः<br> [Bildquelle: Toji Leon. -- <a href="http://www.flickr.com/photos/tojileon/295384395/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/tojileon/295384395/</a>. -- Zugriff am 2009-01-11. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>वेष m.: Kleid, Aussehen, Äußeres</p><p><img src="'+o+'" alt=""><br> Abb.: वेषः<br> वाराणस्याम्<br> [Bildquelle: pyjama. -- <a href="http://www.flickr.com/photos/rpt/319410503/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/rpt/319410503/</a>. -- Zugriff am 2009-01-11. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung,  keine kommerzielle Nutzung, share alike)]</p><p>छन्न n.: Decke, Versteck</p><p>पञ्जर n.: Käfig</p><p><img src="'+u+'" alt=""><br> Abb.: पञ्जरम्<br> Wahrsager mit Papagei in Käfig: der Papagei zieht Zettelchen, auf denen das Schicksal steht<br> Mysore<br> [Bildquelle: prakhar. -- <a href="http://www.flickr.com/photos/prakhar/2735441620/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/prakhar/2735441620/</a>. -- Zugriff am 2009-01-12. --  <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>चाण्डाल । चण्डाल m.: unterste Stufe der <a href="http://de.wikipedia.org/wiki/Dalit" target="_blank" rel="noreferrer">Dalits</a></p><p>स्वयम् Indekl.: selbst, von selbst</p><p>अवनि f.: Erde</p><p>मुहूर्त m.,n.: Augenblick, Moment, rechter Augenblick</p><p>ध्यै 1P ध्यायति : sich vorstellen, denken</p><blockquote><p>Perf. IV दध्यौ<br> Fut. ध्यास्यति<br> Pass. ध्यायते<br> Kaus. ध्यापयति<br> PPP ध्यात<br> Inf. ध्यातुम्<br> Gerundiv ध्येय</p></blockquote><p>आदर m.: Rücksicht, Beachtung, Respekt</p><p><img src="'+h+'" alt=""><br> Abb.: सादरः<br> Amritsar = ਅੰਮ੍ਰਿਤਸਰ<br> [Bildquelle: Koshyk. -- <a href="http://www.flickr.com/photos/kkoshy/2154426738/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/kkoshy/2154426738/</a>. -- Zugriff am 2009-01-11. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>कुतुक n. = कुलूहल n.</p><p>परम 3: fernster, höchster ; पञ्चम्या : besser als, höher als</p><p>शिशु m.: Kind, Junges</p><p><img src="'+b+'" alt=""><br> Abb.: गजशिशुः<br> Sri Lanka<br> [Bildquelle: Carmelo Aquilina. -- <a href="http://www.flickr.com/photos/carmelos-pictures/113895562/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/carmelos-pictures/113895562/</a>. -- Zugriff am 2009-01-11. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_49-5-wiederholungsubung-zur-formenlehre" tabindex="-1">49.5. Wiederholungsübung zur Formenlehre <a class="header-anchor" href="#_49-5-wiederholungsubung-zur-formenlehre" aria-label="Permalink to &quot;49.5. Wiederholungsübung zur Formenlehre&quot;">​</a></h2><p>Bestimmen Sie folgende Formen:</p><ol><li>गृहाणि</li><li>नमानि</li><li>नामानि</li><li>नामनि</li><li>मत्यै</li><li>मन्यै</li><li>मान्यै</li><li>मान्यैः</li><li>अहम्</li><li>अहन्</li><li>आत्थ</li><li>आत्त</li><li>आध्वम्</li><li>अत्थ</li><li>ते</li><li>स्थ</li><li>तस्थ</li><li>तस्य</li><li>दाता</li><li>तता</li><li>तथा</li><li>तदा</li><li>तुद</li><li>शेकिथ</li><li>अनृतम्</li><li>अदूष्यः</li><li>अदुष्यः</li><li>त्वत्</li><li>यदि</li><li>यति</li><li>याति</li><li>यातुः</li><li>यतः</li><li>यातः</li><li>आसीथाः</li><li>वक्थ</li><li>बन्धनीय</li><li>गायी</li><li>मय्हम्</li></ol><h2 id="_49-6-ubersetzungsubung" tabindex="-1">49.6. Übersetzungsübung <a class="header-anchor" href="#_49-6-ubersetzungsubung" aria-label="Permalink to &quot;49.6. Übersetzungsübung&quot;">​</a></h2><p>बान (7. Jhdt. n. Chr.): कादम्बरी, ed. M. R. Kale, 1968, S. 35f.</p><p>Fragen des Königs शूद्रक von विदिशा an den Papagei वैशम्पायन:</p><p>नरपतिरब्रवीत् । आस्तां तावत्सर्वमेवेदम् । अपनयतु नः कुतूहलम् । आवेदयतु भवानादितः प्रभृति कार्त्न्येनात्मनो जन्म कस्मिन्देशे । भवान्कथं जातः । केन वा नाम कृतम् । का माता । कस्ते पिता । कथं वेदानामागमः । कथं शास्त्राणां परिचयः । कुतः कलाः समासादिताः । किं जन्मान्तरानुस्मरणमुत वरप्रदानम् । अथवा विहंगवेषधारी कश्चिच्छन्नं विवससि । क्व वा पूर्वमुषितम् । कियद्वा वयः । कथं पञ्जरबन्धः । कथं चाण्डालहस्तगमनम् । इह वा कथमागमनमिति ।</p><p>वैशम्पायनस्तु स्वयमुपजातकुतूहलेन सबहुमानमवनि्पतिना पृष्टो मुहूर्तमिव ध्यात्वा सादरमब्रवीत् । देव मतीयं कथा । यदि कौतुकमाकर्ण्यताम् ॥</p><p><img src="'+p+'" alt=""><br> Abb.: शुकः (Papagei)<br> Pflaumenkopfsittich <em>= Psittacula cyanocephala</em>[Bildquelle: Candle Tree. -- <a href="http://www.flickr.com/photos/candletree/2529809901/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/candletree/2529809901/</a>. -- Zugriff am 2009-01-12. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung,  keine kommerzielle Nutzung, share alike)]</p>',91)])])}const z=e(m,[["render",c]]);export{w as __pageData,z as default};
